import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory, GameEvent } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, ALL_ITEM_DETAILS } from './constants';
import { CLAN_MASTER_REGISTRY } from './data/master_registry';
import { CharacterController } from './services/CharacterController';
import { EventController } from './services/EventController';
import ClanDashboard from './components/MembersPanel/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement/ClanManagement';
import BreakthroughModal from './components/Xiulian/BreakthroughModal';
import EventModal from './components/events/EventModal';

const SEASON_NAMES = ['', '春', '夏', '秋', '冬'];

const App: React.FC = () => {
    const [state, setState] = useState<GameState>(() => {
        const initializedMembers = INITIAL_MEMBERS.map(m => ({
            ...m,
            rootGrade: CharacterController.getAutoRootGrade(m.roots)
        })) as ClanMember[];

        return {
            year: 1,
            season: 1,
            spiritStones: CLAN_MASTER_REGISTRY.spiritStones,
            merit: CLAN_MASTER_REGISTRY.merit,
            luck: CLAN_MASTER_REGISTRY.luck,
            members: initializedMembers,
            regions: INITIAL_REGIONS,
            buildings: [],
            inventory: CLAN_MASTER_REGISTRY.inventory,
            currentRegionId: '',
            logs: ["太平历初，望月李氏在此立基。"],
            heritagePool: CLAN_MASTER_REGISTRY.heritagePool,
            unlockedPositions: ['家主', '弟子'],
            flags: {},
            eventQueue: [],
            factionReputation: { '魏家': 50, '邵家': 50, '北寒宗': 50 } 
        };
    });

    const [pendingEvents, setPendingEvents] = useState<GameEvent[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const [breakingMemberId, setBreakingMemberId] = useState<string | null>(null);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === id);
            if (!member) return prev;
            const { updatedMember, logs } = CharacterController.updateMember(member, updates, prev.year);
            let updatedMembers = prev.members.map(m => m.id === id ? updatedMember : m);
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '弟子' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers,
                logs: logs.length > 0 ? [...logs, ...prev.logs].slice(0, 30) : prev.logs
            };
        });
    };

    const handleAssignItem = (memberId: string, itemId: number, category: string, quantity: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            const itemDetail = ALL_ITEM_DETAILS[itemId] as any;
            const catKey = category as keyof Inventory;

            if (!member || !itemDetail || (prev.inventory[catKey] as any)[itemId] < quantity) return prev;

            const newClanInventory = { ...prev.inventory };
            (newClanInventory[catKey] as any)[itemId] -= quantity;
            if ((newClanInventory[catKey] as any)[itemId] === 0) delete (newClanInventory[catKey] as any)[itemId];

            const newMemberInventory = { ...member.personalInventory };
            (newMemberInventory[catKey] as any)[itemId] = ((newMemberInventory[catKey] as any)[itemId] || 0) + quantity;

            const updatedMembers = prev.members.map(m => 
                m.id === memberId ? { ...m, personalInventory: newMemberInventory } : m
            );

            return {
                ...prev,
                inventory: newClanInventory,
                members: updatedMembers,
                logs: [`【分配】家族将 ${itemDetail.name} x${quantity} 分配给了 ${member.name}。`, ...prev.logs].slice(0, 30)
            };
        });
    };

    const handleContributeItem = (memberId: string, itemId: number, category: string, quantity: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;

            const catKey = category as keyof Inventory;
            const currentQty = (member.personalInventory[catKey] as any)[itemId] || 0;
            if (currentQty < quantity) return prev;

            const newMemberInventory = { ...member.personalInventory };
            (newMemberInventory[catKey] as any)[itemId] -= quantity;
            if ((newMemberInventory[catKey] as any)[itemId] <= 0) {
                delete (newMemberInventory[catKey] as any)[itemId];
            }

            const newClanInventory = { ...prev.inventory };
            if (catKey !== 'paper') {
                (newClanInventory[catKey] as any)[itemId] = ((newClanInventory[catKey] as any)[itemId] || 0) + quantity;
            }

            const itemDetail = ALL_ITEM_DETAILS[itemId] as any;

            return {
                ...prev,
                inventory: newClanInventory,
                members: prev.members.map(m => m.id === memberId ? { ...m, personalInventory: newMemberInventory } : m),
                logs: [`【上交】${member.name} 将 ${itemDetail?.name || '物品'} x${quantity} 上交给家族。`, ...prev.logs].slice(0, 30)
            };
        });
    };

    const handleNextTurn = async () => {
        setIsProcessing(true);
        let turnLogs: string[] = [];
        let newEvents: GameEvent[] = [];

        const currentYear = state.year;
        const currentSeason = state.season;
        const nextSeason = currentSeason >= 4 ? 1 : currentSeason + 1;
        const isYearIncrement = currentSeason === 4;

        // 建筑营造进度逻辑
        const updatedBuildings = state.buildings.map(b => {
            if (!b.isFinished) {
                const rem = b.turnsRemaining - 1;
                if (rem <= 0) {
                    turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${BUILDING_TYPES[b.type].name} 营造完成，族运得以上升。`);
                    return { ...b, isFinished: true, turnsRemaining: 0 };
                }
                return { ...b, turnsRemaining: rem };
            }
            return b;
        });

        const updatedRegions = state.regions.map(r => {
            let nr = { ...r };
            if (nr.activeMission) {
                const rem = nr.activeMission.turnsRemaining - 1;
                if (rem <= 0) {
                    const member = state.members.find(m => m.id === nr.activeMission!.memberId);
                    if (member) {
                        const missionEvent = EventController.generateMissionResult(member, nr, currentYear);
                        newEvents.push(missionEvent);
                    }
                    nr.activeMission = undefined;
                } else {
                    nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                }
            }
            return nr;
        });

        let guardStones = 0;
        let guardMerit = 0;
        const itemGains: any = { herbs: {}, minerals: {}, pills: {}, weapons: {}, methods: {}, scrolls: {} };
        let hasItemGains = false;

        state.regions.forEach(region => {
            if (region.guardMemberId && region.production) {
                if (region.production.stones) guardStones += region.production.stones;
                if (region.production.merit) guardMerit += region.production.merit;
                if (region.production.items) {
                    Object.entries(region.production.items).forEach(([idStr, qty]) => {
                        const id = parseInt(idStr);
                        const detail = ALL_ITEM_DETAILS[id];
                        if (detail) {
                            const cat = (detail as any).category;
                            const catKey = cat === 'herb' ? 'herbs' :
                                           cat === 'mineral' ? 'minerals' :
                                           cat === 'pill' ? 'pills' :
                                           cat === 'weapon' ? 'weapons' :
                                           cat === 'method' ? 'methods' : 'scrolls';

                            itemGains[catKey][id] = (itemGains[catKey][id] || 0) + qty;
                            hasItemGains = true;
                        }
                    });
                }
                const guardingMember = state.members.find(m => m.id === region.guardMemberId);
                if (guardingMember) {
                    turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${guardingMember.name} 驻守 ${region.name}，上缴物资。`);
                }
            }
        });

        const updatedMembers = state.members.map(m => {
            const { updatedMember, logs } = CharacterController.processTurn(m, currentYear, isYearIncrement);
            turnLogs.push(...logs);
            return updatedMember;
        });

        if (Math.random() > 0.6) {
            newEvents.push(EventController.generateNextEvent({ ...state, members: updatedMembers, regions: updatedRegions, buildings: updatedBuildings }));
        }

        setState(prev => {
            const newInventory = { ...prev.inventory };
            if (hasItemGains) {
                Object.keys(itemGains).forEach(cat => {
                    const typedCat = cat as keyof Inventory;
                    if (typedCat === 'paper') return;
                    Object.entries(itemGains[typedCat]).forEach(([id, qty]) => {
                        const itemId = parseInt(id);
                        newInventory[typedCat][itemId] = (newInventory[typedCat][itemId] || 0) + (qty as number);
                    });
                });
            }

            return {
                ...prev,
                year: isYearIncrement ? prev.year + 1 : prev.year,
                season: nextSeason,
                members: updatedMembers,
                regions: updatedRegions,
                buildings: updatedBuildings,
                spiritStones: prev.spiritStones + 50 + guardStones,
                merit: prev.merit + 2 + guardMerit,
                inventory: newInventory,
                logs: [...turnLogs, ...prev.logs].slice(0, 30)
            };
        });

        if (newEvents.length > 0) {
            setPendingEvents(newEvents);
        }

        setIsProcessing(false);
    };

    const handleChoice = (choiceKey: 'choiceA' | 'choiceB') => {
        if (pendingEvents.length === 0) return;
        const currentEvent = pendingEvents[0];
        const updates = EventController.processEventChoice(state, currentEvent, choiceKey);

        setState(prev => ({ ...prev, ...updates }));
        setPendingEvents(prev => prev.slice(1));
    };

    const handleBreakthroughAttempt = (memberId: string, success: boolean, usedPillId?: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;
            const { updatedMember, log } = CharacterController.breakthrough(member, success, prev.year, usedPillId);
            return {
                ...prev,
                members: prev.members.map(m => m.id === memberId ? updatedMember : m),
                heritagePool: success ? prev.heritagePool + 10 : prev.heritagePool,
                logs: [log, ...prev.logs].slice(0, 30)
            };
        });
        setBreakingMemberId(null);
    };

    const handleSelectRegion = (r: Region | null) => {
        if (r && r.id === 'li_clan_home') setIsManagementVisible(true);
        else setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
    };

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (!info || state.spiritStones < info.baseCost) return;

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, {
                id: `${type}_${Date.now()}`,
                type,
                level: 1,
                assignedMemberId: null,
                isFinished: false,
                turnsRemaining: info.baseTurns
            }],
            logs: [`【营造】决定在家族祖地营造 ${info.name}，扣除灵石 ${info.baseCost}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleCancelBuilding = (id: string) => {
        const building = state.buildings.find(b => b.id === id);
        if (!building || building.isFinished) return;
        const info = BUILDING_TYPES[building.type];

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones + info.baseCost,
            buildings: prev.buildings.filter(b => b.id !== id),
            logs: [`【营造】取消了 ${info.name} 的营造计划，返还灵石 ${info.baseCost}。`, ...prev.logs].slice(0, 30)
        }));
    };

    return (
        <div className="h-full w-full flex flex-col bg-bg-main text-text-main overflow-hidden select-none font-sans">
            <header className="h-16 bg-bg-panel border-b border-border-soft flex items-center justify-between px-8 z-40 shadow-xl shrink-0">
                <div className="flex items-center gap-12">
                    <h1 className="font-serif font-h1 text-accent-gold tracking-[0.2em]">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-8 items-center border-l border-border-soft pl-8">
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">灵石</span>
                            <span className="font-value text-accent-gold">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">功德</span>
                            <span className="font-value text-blue-400">💠 {state.merit}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">岁时</span>
                            <span className="font-value text-text-main">{state.year}载 · {SEASON_NAMES[state.season]}</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-bg-main border border-border-soft text-text-muted rounded-sm font-caption font-bold hover:border-accent-jade transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-sm border transition-all font-caption font-bold ${isDashboardVisible ? 'bg-accent-jade/20 border-accent-jade text-accent-jade' : 'bg-bg-main border-border-soft text-text-disabled'}`}>📜 族谱</button>
                    <button onClick={handleNextTurn} disabled={isProcessing || pendingEvents.length > 0} className="bg-accent-jade hover:brightness-110 disabled:opacity-30 text-bg-main px-8 py-2 rounded-sm font-sans font-body font-bold transition-all shadow-lg">{isProcessing ? '推演中' : '岁时轮转'}</button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                <div className="flex-1 relative bg-bg-main">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        reputation={state.factionReputation}
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={handleSelectRegion} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} 
                    />

                    <div className={`absolute bottom-6 left-6 transition-all duration-300 bg-bg-panel/95 border border-border-soft rounded-sm shadow-2xl z-20 flex flex-col overflow-hidden ${isConsoleCollapsed ? 'w-48 h-10' : 'w-80 h-64'}`}>
                        <div 
                            className="flex justify-between items-center px-4 py-2 border-b border-border-soft bg-bg-main/50 shrink-0 cursor-pointer group hover:bg-bg-panel/80 transition-all" 
                            onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)}
                        >
                            <span className="font-sans font-caption font-bold text-text-muted group-hover:text-text-main transition-colors">族史摘要</span>
                            <div className="flex items-center gap-3">
                                <span className={`text-[10px] text-accent-gold transition-transform duration-300 ${isConsoleCollapsed ? '-rotate-180' : 'rotate-0'}`}>
                                    ▼
                                </span>
                            </div>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                {state.logs.map((log, i) => (
                                    <p key={i} className="font-sans font-caption text-text-muted leading-relaxed border-b border-border-soft/30 pb-2">
                                        <span className="text-accent-jade mr-2">◈</span> {log}
                                    </p>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                {isDashboardVisible && (
                    <div className="w-80 h-full border-l border-border-soft flex flex-col shrink-0">
                        <ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={() => {}} onOpenBreakthrough={(id) => setBreakingMemberId(id)} onContributeItem={handleContributeItem} />
                    </div>
                )}
            </main>

            {isManagementVisible && (
                <ClanManagement 
                    state={state} 
                    onUpdateMember={handleUpdateMember} 
                    onUpdateBuilding={(id, u) => setState(p => ({ ...p, buildings: p.buildings.map(b => b.id === id ? { ...b, ...u } : b) }))} 
                    onAddBuilding={handleAddBuilding} 
                    onCancelBuilding={handleCancelBuilding}
                    onAssignBuilding={(b, m) => setState(p => ({ ...p, buildings: p.buildings.map(build => build.id === b ? { ...build, assignedMemberId: m } : build) }))} 
                    onAssignItem={handleAssignItem}
                    onClose={() => setIsManagementVisible(false)} 
                />
            )}

            {pendingEvents.length > 0 && (
                <EventModal event={pendingEvents[0]} onChoice={handleChoice} />
            )}

            {breakingMemberId && (
                <BreakthroughModal 
                    member={state.members.find(m => m.id === breakingMemberId)!}
                    onClose={() => setBreakingMemberId(null)}
                    onAttempt={(success, pillId) => handleBreakthroughAttempt(breakingMemberId, success, pillId)}
                />
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo } from 'react';
import { GameState, ClanMember, Building } from '../../types';
import Tooltip from '../Shared/Tooltip';
import { useTooltip } from '../Shared/useTooltip';

// 导入同目录 Tabs 文件夹下的子标签页组件
import StatusTab from './Tabs/StatusTab';
import WarehouseTab from './Tabs/WarehouseTab';
import BuildingsTab from './Tabs/BuildingsTab';
import PositionsTab from './Tabs/PositionsTab';
import AlchemyTab from './Tabs/AlchemyTab';
import SmithingTab from './Tabs/SmithingTab';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onUpdateBuilding: (id: string, updates: Partial<Building>) => void;
    onAddBuilding: (type: string) => void;
    onCancelBuilding?: (id: string) => void;
    onAssignBuilding: (buildingId: string, memberId: string | null) => void;
    onAssignItem?: (memberId: string, itemId: number, category: string, quantity: number) => void;
    onClose: () => void;
    onUnlockPosition?: (pos: string, cost: number) => void;
}

const ClanManagement: React.FC<Props> = ({ state, onUpdateMember, onAddBuilding, onCancelBuilding, onAssignBuilding, onAssignItem, onClose, onUnlockPosition }) => {
    const [activeTab, setActiveTab] = useState<'status' | 'buildings' | 'positions' | 'alchemy' | 'smithing' | 'warehouse'>('status');
    const { tooltip, showTooltip, hideTooltip } = useTooltip();

    const alreadyAssignedIds = useMemo(() => {
        return state.buildings.map(b => b.assignedMemberId).filter(id => id !== null) as string[];
    }, [state.buildings]);

    const hasBuilding = (type: string) => state.buildings.some(b => b.type === type && b.isFinished);

    const alchemyRoom = state.buildings.find(b => b.type === 'AlchemyRoom');
    const smithy = state.buildings.find(b => b.type === 'Smithy');

    const tabs = [
        { id: 'status', name: '概况', icon: '📜', color: 'yellow' },
        { id: 'warehouse', name: '仓库', icon: '🏯', color: 'amber' },
        { id: 'buildings', name: '营造', icon: '🏗️', color: 'yellow' },
        { id: 'positions', name: '职位', icon: '👔', color: 'yellow' },
    ];

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 overflow-hidden select-none">
            <Tooltip state={tooltip} />

            <div className="relative w-full max-w-6xl h-[85vh] bg-[#1a1310] border-[8px] border-[#4a3728] rounded-sm shadow-2xl flex flex-col font-serif">
                {/* 页眉导航 */}
                <div className="h-16 bg-[#2c1810] border-b border-yellow-900/30 flex items-center px-6 shrink-0 gap-6">
                    <h2 className="text-2xl font-cursive text-yellow-600 pr-4 border-r border-yellow-900/20">望月大社</h2>
                    <div className="flex h-full overflow-x-auto scrollbar-hide">
                        {tabs.map(t => (
                            <button 
                                key={t.id} 
                                onClick={() => setActiveTab(t.id as any)} 
                                className={`whitespace-nowrap px-6 h-full text-sm font-bold border-b-2 transition-all flex items-center gap-2 
                                    ${activeTab === t.id 
                                        ? `border-${t.color}-500 text-${t.color}-500 bg-${t.color}-900/10` 
                                        : 'border-transparent text-gray-500 hover:text-gray-400'}`}
                            >
                                <span className="text-lg opacity-70">{t.icon}</span> {t.name}
                            </button>
                        ))}
                        {hasBuilding('AlchemyRoom') && (
                            <button 
                                onClick={() => setActiveTab('alchemy')} 
                                className={`whitespace-nowrap px-6 h-full text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'alchemy' ? 'border-pink-500 text-pink-500 bg-pink-900/10' : 'border-transparent text-gray-500 hover:text-gray-400'}`}
                            >
                                <span>⚗️</span> 炼丹
                            </button>
                        )}
                        {hasBuilding('Smithy') && (
                            <button 
                                onClick={() => setActiveTab('smithing')} 
                                className={`whitespace-nowrap px-6 h-full text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'smithing' ? 'border-blue-500 text-blue-500 bg-blue-900/10' : 'border-transparent text-gray-500 hover:text-gray-400'}`}
                            >
                                <span>🔨</span> 炼器
                            </button>
                        )}
                    </div>
                    <button onClick={onClose} className="ml-auto w-10 h-10 flex items-center justify-center text-gray-500 hover:text-white text-3xl transition-colors font-bold">×</button>
                </div>

                {/* 内容区域 */}
                <div className="flex-1 overflow-y-auto p-8 custom-scrollbar bg-[#140f0d]">
                    {activeTab === 'status' && <StatusTab state={state} />}
                    {activeTab === 'warehouse' && (
                        <WarehouseTab 
                            inventory={state.inventory} 
                            members={state.members}
                            onAssignItem={onAssignItem}
                            showTooltip={showTooltip} 
                            hideTooltip={hideTooltip} 
                        />
                    )}
                    {activeTab === 'buildings' && (
                        <BuildingsTab 
                            buildings={state.buildings} 
                            spiritStones={state.spiritStones} 
                            onAddBuilding={onAddBuilding} 
                            onCancelBuilding={onCancelBuilding}
                        />
                    )}
                    {activeTab === 'positions' && (
                        <PositionsTab 
                            members={state.members} 
                            unlockedPositions={state.unlockedPositions} 
                            merit={state.merit} 
                            onUpdateMember={onUpdateMember} 
                            onUnlockPosition={onUnlockPosition || (() => {})} 
                        />
                    )}
                    {activeTab === 'alchemy' && alchemyRoom && (
                        <AlchemyTab 
                            building={alchemyRoom} 
                            members={state.members} 
                            alreadyAssignedIds={alreadyAssignedIds} 
                            onAssignBuilding={onAssignBuilding} 
                        />
                    )}
                    {activeTab === 'smithing' && smithy && (
                        <SmithingTab 
                            building={smithy} 
                            members={state.members} 
                            alreadyAssignedIds={alreadyAssignedIds} 
                            onAssignBuilding={onAssignBuilding} 
                        />
                    )}
                </div>
            </div>
        </div>
    );
};

export default ClanManagement;

import React, { useState } from 'react';
import { Building, BuildingCategory } from '../../../types';
import { BUILDING_TYPES } from '../../../constants';

interface Props {
    buildings: Building[];
    spiritStones: number;
    onAddBuilding: (type: string) => void;
    onCancelBuilding?: (id: string) => void;
}

const BuildingsTab: React.FC<Props> = ({ buildings, spiritStones, onAddBuilding, onCancelBuilding }) => {
    const [confirmingBuildType, setConfirmingBuildType] = useState<string | null>(null);
    const [confirmingCancelId, setConfirmingCancelId] = useState<string | null>(null);

    const getBuildingProgress = (b: Building) => {
        const total = BUILDING_TYPES[b.type].baseTurns;
        const current = total - b.turnsRemaining;
        return (current / total) * 100;
    };

    const handleConfirmBuild = () => {
        if (confirmingBuildType) {
            onAddBuilding(confirmingBuildType);
            setConfirmingBuildType(null);
        }
    };

    const handleConfirmCancel = () => {
        if (confirmingCancelId && onCancelBuilding) {
            onCancelBuilding(confirmingCancelId);
            setConfirmingCancelId(null);
        }
    };

    const renderBuildingList = (category: BuildingCategory) => {
        return (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {Object.entries(BUILDING_TYPES)
                    .filter(([_, info]) => info.category === category)
                    .map(([type, info]) => {
                        const b = buildings.find(building => building.type === type);
                        const isBuilding = b && !b.isFinished;
                        const isFinished = b && b.isFinished;
                        const canAfford = spiritStones >= info.baseCost;

                        return (
                            <div key={type} className={`p-6 bg-black/40 border rounded shadow-lg transition-all flex flex-col justify-between ${isFinished ? 'border-yellow-900/40 opacity-70' : 'border-yellow-900/20'}`}>
                                <div>
                                    <div className="flex justify-between items-center mb-4">
                                        <span className="text-3xl">{info.icon}</span>
                                        <span className="text-[10px] bg-yellow-900/20 px-2 py-1 rounded text-yellow-600 font-bold uppercase tracking-widest">{info.category}</span>
                                    </div>
                                    <h4 className="text-lg font-bold text-yellow-500 mb-2">{info.name}</h4>
                                    <p className="text-xs text-gray-500 leading-relaxed mb-4">{info.desc}</p>
                                </div>
                                <div className="space-y-4 pt-4 border-t border-yellow-900/10">
                                    <div className="flex justify-between items-center text-sm">
                                        <span className="text-gray-500">营造费用</span>
                                        <span className={`font-mono font-bold ${canAfford ? 'text-yellow-400' : 'text-red-500'}`}>✨ {info.baseCost}</span>
                                    </div>

                                    {isBuilding ? (
                                        <div className="space-y-3">
                                            <div className="w-full bg-black/40 h-1.5 rounded-full overflow-hidden">
                                                <div className="bg-yellow-600 h-full transition-all" style={{ width: `${getBuildingProgress(b)}%` }}></div>
                                            </div>
                                            <p className="text-[10px] text-gray-500 text-center">正在营造... 还需 {b.turnsRemaining} 载</p>
                                            <button 
                                                onClick={() => setConfirmingCancelId(b.id)}
                                                className="w-full py-1.5 bg-red-900/10 border border-red-900/30 text-red-500 text-[10px] font-bold rounded hover:bg-red-900/30 transition-all uppercase tracking-tighter"
                                            >
                                                取消营造
                                            </button>
                                        </div>
                                    ) : (
                                        <button 
                                            disabled={isFinished || !canAfford}
                                            onClick={() => setConfirmingBuildType(type)}
                                            className={`w-full py-2 rounded font-bold text-xs tracking-widest transition-all ${isFinished ? 'bg-gray-800 text-gray-500 cursor-not-allowed' : (canAfford ? 'bg-yellow-800 text-yellow-100 hover:bg-yellow-700' : 'bg-red-900/20 text-red-500 border border-red-900/30 cursor-not-allowed')}`}
                                        >
                                            {isFinished ? '已经拥有' : (canAfford ? '开始建造' : '灵石不足')}
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
            </div>
        );
    };

    return (
        <div className="space-y-12 animate-fade-in max-w-5xl mx-auto pb-10">
            <div>
                <h3 className="text-blue-700 text-sm font-bold mb-6 border-l-4 border-blue-700 pl-4 tracking-widest">家族功能建筑</h3>
                {renderBuildingList('家族功能')}
            </div>
            <div>
                <h3 className="text-emerald-700 text-sm font-bold mb-6 border-l-4 border-emerald-700 pl-4 tracking-widest">修行基础建筑</h3>
                {renderBuildingList('修行基础')}
            </div>

            {/* 确认建造弹窗 */}
            {confirmingBuildType && (
                <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-[#1a1310] border-4 border-[#4a3728] p-8 rounded-sm shadow-2xl max-w-sm w-full text-center animate-fade-in">
                        <h4 className="text-2xl font-cursive text-yellow-500 mb-6 tracking-widest">营造诏书</h4>
                        <div className="bg-black/60 p-6 rounded-sm border border-white/5 mb-8">
                            <p className="text-gray-300 text-sm leading-relaxed font-serif">
                                是否消耗灵石 <span className="text-yellow-500 font-bold">✨ {BUILDING_TYPES[confirmingBuildType].baseCost}</span> 开始营造 <span className="text-yellow-400 font-bold">{BUILDING_TYPES[confirmingBuildType].name}</span>？
                            </p>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmingBuildType(null)} className="flex-1 py-2.5 bg-black/40 border border-[#4a3728] text-gray-500 rounded-sm font-bold hover:text-gray-300 transition-all text-xs tracking-widest">暂缓</button>
                            <button onClick={handleConfirmBuild} className="flex-1 py-2.5 bg-yellow-900/80 text-yellow-100 rounded-sm font-bold hover:bg-yellow-800 transition-all shadow-xl text-xs tracking-widest border border-yellow-600/30">动工</button>
                        </div>
                    </div>
                </div>
            )}

            {/* 确认取消弹窗 */}
            {confirmingCancelId && (
                <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-[#1a1310] border-4 border-[#4a3728] p-8 rounded-sm shadow-2xl max-w-sm w-full text-center animate-fade-in">
                        <h4 className="text-2xl font-cursive text-red-500 mb-6 tracking-widest">废止营造</h4>
                        <div className="bg-black/60 p-6 rounded-sm border border-white/5 mb-8">
                            <p className="text-gray-300 text-sm leading-relaxed font-serif">
                                是否取消 <span className="text-yellow-400 font-bold">{BUILDING_TYPES[buildings.find(b => b.id === confirmingCancelId)!.type].name}</span> 的营造计划？<br/>
                                确认后将全额返还灵石 <span className="text-yellow-500 font-bold">✨ {BUILDING_TYPES[buildings.find(b => b.id === confirmingCancelId)!.type].baseCost}</span>。
                            </p>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmingCancelId(null)} className="flex-1 py-2.5 bg-black/40 border border-[#4a3728] text-gray-500 rounded-sm font-bold hover:text-gray-300 transition-all text-xs tracking-widest">继续营造</button>
                            <button onClick={handleConfirmCancel} className="flex-1 py-2.5 bg-red-900/80 text-white rounded-sm font-bold hover:bg-red-800 transition-all shadow-xl text-xs tracking-widest border border-red-600/30">确认废止</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

