            <div className="flex-1 bg-black/40 border border-white/5 rounded-xl p-6 flex flex-col overflow-hidden">
                <h4 className="text-amber-500 text-sm font-bold mb-4 flex items-center gap-2 border-b border-white/5 pb-2">
                    <span>📜</span> 家族传承功法
                </h4>
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                    {familyMethods.length > 0 ? (
                        <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                            {familyMethods.map(item => {
                                const detail = (ALL_ITEM_DETAILS as any)[item.id];
                                return (
                                    <div key={item.id} className="p-3 bg-[#1a1612] border border-amber-900/20 rounded flex flex-col gap-1 group hover:border-amber-600 transition-all">
                                        <p className="text-yellow-100 font-bold text-xs truncate">{detail?.name || '未知功法'}</p>
                                        <p className="text-[10px] text-gray-500">{detail?.gradeText || '品阶未知'}</p>
                                        <div className="mt-2 text-right">
                                            <span className="text-[10px] text-amber-800 font-mono">余量：{item.count}</span>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-gray-700 italic gap-2">
                            <span className="text-4xl opacity-10">📖</span>
                            <p className="text-xs">族中目前无任何公有功法存本</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default LibraryTab;

